def transition(state, action):
    s = dict(state)
    wards = {w: dict(v) for w, v in s.get("wards", {}).items()}
    patients = {p: dict(v) for p, v in s.get("patients", {}).items()}
    waitlist = [dict(r) for r in s.get("waitlist", [])]
    pending = dict(s.get("pending", {}) or {})

    name = action.get("name")
    params = action.get("params") or {}

    def cap(w):
        return wards.get(w, {}).get("capacity", 0)

    def occ(w):
        return sum(1 for r in patients.values() if r.get("ward") == w)

    def free(w):
        return cap(w) - occ(w)

    def first_free_ward(exclude=None):
        # deterministic: lowest ward name (by sort) that has a free bed
        for w in sorted(wards):
            if w != exclude and free(w) > 0:
                return w
        return None

    event = "noop"

    if name == "admit":
        # Resolve the candidate: explicit param, then a perceived request,
        # then the head of the waitlist.
        req = None
        pid = params.get("patient")
        if pid is not None:
            for r in waitlist:
                if r.get("id") == pid:
                    req = r
                    break
            if req is None and pending.get("id") == pid:
                req = pending
        if req is None and pending.get("id") is not None:
            req = pending
        if req is None and waitlist:
            req = waitlist[0]

        if req is not None:
            ward = params.get("ward") or req.get("ward") or first_free_ward()
            if ward in wards and free(ward) > 0:
                patients[req["id"]] = {"ward": ward,
                                       "acuity": int(req.get("acuity", 3))}
                waitlist = [r for r in waitlist if r.get("id") != req["id"]]
                if pending.get("id") == req["id"]:
                    pending = {}
                s["admitted_count"] = int(s.get("admitted_count", 0)) + 1
                event = "admit %s -> %s" % (req["id"], ward)
            else:
                # No free bed where this patient could go: keep them waiting.
                if pending.get("id") == req.get("id") and not any(
                        r.get("id") == req["id"] for r in waitlist):
                    waitlist = waitlist + [{"id": req["id"],
                                            "acuity": int(req.get("acuity", 3))}]
                    pending = {}
                event = "admit_blocked: no free bed"

    elif name == "transfer":
        pid = params.get("patient")
        if pid is None and patients:
            # default: move from the fullest ward (tie -> ward name) the
            # patient with the lowest acuity (tie -> patient id).
            src = max(sorted(wards), key=occ)
            in_src = sorted((p for p, r in patients.items()
                             if r.get("ward") == src),
                            key=lambda p: (patients[p].get("acuity", 0), p))
            pid = in_src[0] if in_src else None
        if pid in patients:
            cur = patients[pid].get("ward")
            dst = params.get("to_ward") or first_free_ward(exclude=cur)
            if dst in wards and dst != cur and free(dst) > 0:
                patients[pid] = dict(patients[pid])
                patients[pid]["ward"] = dst
                s["transferred_count"] = int(s.get("transferred_count", 0)) + 1
                event = "transfer %s: %s -> %s" % (pid, cur, dst)
            else:
                event = "transfer_blocked: no free bed"

    elif name == "discharge":
        pid = params.get("patient")
        if pid is None and patients:
            # default: discharge the lowest-acuity patient (tie -> id).
            pid = sorted(patients,
                         key=lambda p: (patients[p].get("acuity", 0), p))[0]
        if pid in patients:
            ward = patients[pid].get("ward")
            del patients[pid]
            s["discharged_count"] = int(s.get("discharged_count", 0)) + 1
            event = "discharge %s from %s" % (pid, ward)

    # --- commit entities and recompute derived views (keeps the invariant) ---
    s["wards"] = wards
    s["patients"] = patients
    s["waitlist"] = waitlist
    s["pending"] = pending
    s["occupancy"] = {w: occ(w) for w in sorted(wards)}
    s["total_capacity"] = sum(cap(w) for w in wards)
    s["occupied_beds"] = len(patients)
    s["free_beds"] = s["total_capacity"] - s["occupied_beds"]
    s["waiting_count"] = len(waitlist)
    s["time"] = int(s.get("time", 0)) + 1
    s["last_event"] = event
    return s

