def perceive(data):
    # Accept a structured request dict ...
    if isinstance(data, dict):
        pid = data.get("id") or data.get("patient")
        if pid is None:
            return {}
        req = {"id": str(pid), "acuity": int(data.get("acuity", 3))}
        ward = data.get("ward")
        if ward is not None:
            req["ward"] = str(ward)
        return {"pending": req}
    # ... or a free-text note like "admit P9 acuity 5 ward surgical".
    toks = str(data).replace(",", " ").split()
    low = [t.lower() for t in toks]
    req = {"acuity": 3}
    for i, t in enumerate(low):
        nxt = toks[i + 1] if i + 1 < len(toks) else None
        if t in ("patient", "id", "admit") and nxt is not None:
            req["id"] = str(nxt)
        elif t == "acuity" and nxt is not None:
            try:
                req["acuity"] = int(nxt)
            except (ValueError, TypeError):
                pass
        elif t == "ward" and nxt is not None:
            req["ward"] = str(nxt)
    return {"pending": req} if req.get("id") else {}
